@lru_cache(maxsize=1)
def _ssl_context() -> ssl.SSLContext:
    ctx = ssl.create_default_context()
    ctx.check_hostname = False
    ctx.verify_mode = ssl.CERT_NONE
    return ctx


@lru_cache(maxsize=1)
def _currency_boc_safe_latest() -> dict[str, Any] | None:
    if ak is None:
        return None
    try:
        df = ak.currency_boc_safe()
        if df is None or df.empty or "美元" not in df.columns:
            return None
        df = df.dropna(subset=["美元"])
        if df.empty:
            return None
        last = df.iloc[-1]
        latest = float(last["美元"]) / 100
        prev = float(df.iloc[-2]["美元"]) / 100 if len(df) >= 2 else None
        change_pct = ((latest - prev) / prev * 100) if prev else None
        return {
            "price": latest,
            "change_pct": change_pct,
            "source": "akshare_currency_boc_safe_proxy",
            "date": str(last.get("日期", "")),
        }
    except Exception:
        return None


