SEARCH_TIMEOUT_SECONDS = 20
YFINANCE_TIMEOUT_SECONDS = 8


def _run_with_timeout(fn, seconds: int):
    box: dict[str, Any] = {"result": None, "error": None}

    def runner() -> None:
        try:
            box["result"] = fn()
        except Exception as exc:  # noqa: BLE001
            box["error"] = exc

    thread = threading.Thread(target=runner, daemon=True)
    thread.start()
    thread.join(seconds)
    if thread.is_alive():
        raise TimeoutError(f"timeout after {seconds}s")
    if box["error"] is not None:
        raise box["error"]
    return box["result"]


def run_json(cmd: list[str]) -> dict[str, Any]:
    proc = subprocess.run(cmd, capture_output=True, text=True, check=True, timeout=SEARCH_TIMEOUT_SECONDS)
    return json.loads(proc.stdout)


def unwrap_yahoo_url(raw_url: str) -> str:
    try:
        if '/RU=' in raw_url:
            part = raw_url.split('/RU=', 1)[1]
            target = part.split('/RK=', 1)[0].rstrip('/')
            return unquote(target)
        parsed = urlparse(raw_url)
        ru_vals = parse_qs(parsed.query).get('RU', [])
        if ru_vals:
            return unquote(ru_vals[0])
        return raw_url
    except Exception:
        return raw_url


def clean_title(title: str) -> str:
    title = " ".join(title.split())
    for sep in ["Reutersstock market today", "Reuters ", "...", "| Breaking Stock Market News"]:
        if sep in title and len(title) > 120:
            title = title.split(sep)[0].strip() or title
    return title[:160].strip(" -|")


def domain(url: str) -> str:
    try:
        return urlparse(url).netloc.replace("www.", "")
    except Exception:
        return ""


def _safe_float(value: Any) -> float | None:
    if value is None:
        return None
    if isinstance(value, (int, float)):
        return float(value)
    text = str(value).strip().replace(",", "")
    if not text or text in {"--", "None", "nan", "NaN"}:
        return None
    try:
        return float(text)
    except Exception:
        return None


def _round_value(value: float | None, digits: int = 2) -> float | str:
    if value is None:
        return "-"
    return round(float(value), digits)


def _format_market_result(price: float | None, change_pct: float | None, source: str, *, error: str | None = None) -> dict[str, Any]:
    result: dict[str, Any] = {
        "price": _round_value(price),
        "change_pct": _round_value(change_pct),
        "source": source,
    }
    if error:
        result["error"] = error
    return result


def _extract_sina_payload(raw_text: str) -> str:
    match = re.search(r'="([^"]*)"', raw_text)
    return match.group(1) if match else ""


def _fetch_sina_text(code: str) -> str:
    url = f"https://hq.sinajs.cn/list={code}"
    req = urllib.request.Request(
        url,
        headers={
            "Referer": "https://finance.sina.com.cn",
            "User-Agent": "Mozilla/5.0",
        },
    )
    with urllib.request.urlopen(req, timeout=10, context=_ssl_context()) as resp:
        return resp.read().decode("gbk", errors="ignore").strip()


def _fetch_yfinance_snapshot(ticker: str) -> dict[str, Any]:
    if yf is None:
        raise RuntimeError("yfinance not installed")

    def fetch_history():
        return yf.Ticker(ticker).history(period="5d", timeout=YFINANCE_TIMEOUT_SECONDS)

    hist = _run_with_timeout(fetch_history, YFINANCE_TIMEOUT_SECONDS + 2)
    if len(hist) == 0:
        raise RuntimeError(f"empty yfinance history for {ticker}")
    close = _safe_float(hist["Close"].iloc[-1])
    prev_close = _safe_float(hist["Close"].iloc[-2]) if len(hist) >= 2 else _safe_float(hist["Open"].iloc[-1])
    change_pct = ((close - prev_close) / prev_close * 100) if close is not None and prev_close else None
    return _format_market_result(close, change_pct, "yfinance_fallback")


def _fetch_a_index_snapshot(code: str, fallback_ticker: str) -> dict[str, Any]:
    errors: list[str] = []

    if tencent_realtime is not None:
        try:
            result = tencent_realtime(code)
            if getattr(result, "valid", False) and _safe_float(getattr(result, "price", None)):
                return _format_market_result(
                    _safe_float(result.price),
                    _safe_float(result.change_pct),
                    "tencent_dual_source",
                )
            errors.append(f"tencent:{getattr(result, 'error', 'invalid')}")
        except Exception as exc:
            errors.append(f"tencent:{exc}")

    if sina_realtime is not None:
        try:
            result = sina_realtime(code)
            if getattr(result, "valid", False) and _safe_float(getattr(result, "price", None)):
                change_pct = _safe_float(getattr(result, "change_pct", None))
                if change_pct == 0:
                    change_pct = None
                return _format_market_result(
                    _safe_float(result.price),
                    change_pct,
                    "sina_dual_source",
                )
            errors.append(f"sina:{getattr(result, 'error', 'invalid')}")
        except Exception as exc:
            errors.append(f"sina:{exc}")

    try:
        return _fetch_yfinance_snapshot(fallback_ticker)
    except Exception as exc:
        errors.append(f"yfinance:{exc}")
        return _format_market_result(None, None, "failed", error=" | ".join(errors))


def _fetch_hk_index_snapshot(code: str, fallback_ticker: str) -> dict[str, Any]:
    errors: list[str] = []
    try:
        payload = _extract_sina_payload(_fetch_sina_text(code))
        parts = payload.split(",")
        if len(parts) >= 9:
            # 新浪港股指数字段在不同时间段会有漂移：优先取现值位，其次退回昨收位
            price = _safe_float(parts[6]) or _safe_float(parts[3]) or _safe_float(parts[2])
            prev_close = _safe_float(parts[3]) or _safe_float(parts[2])
            change_pct = _safe_float(parts[8])
            if change_pct is None and price is not None and prev_close:
                change_pct = (price - prev_close) / prev_close * 100
            if price is not None:
                return _format_market_result(price, change_pct, "sina_hk_index")
        errors.append("sina:payload_invalid")
    except Exception as exc:
        errors.append(f"sina:{exc}")

    try:
        return _fetch_yfinance_snapshot(fallback_ticker)
    except Exception as exc:
        errors.append(f"yfinance:{exc}")
        return _format_market_result(None, None, "failed", error=" | ".join(errors))


