    return "隔夜消息面对风险资产影响偏谨慎，资金更关注防御板块和确定性方向。"


def infer_conclusion(text: str, nature: str, bias_text: str, tone: str, positive: list[str], negative: list[str]) -> str:
    t = text.lower()
    if "地缘冲突" in nature and any(k in t for k in ["oil", "crude", "energy"]):
        return f"如果油价继续顶着走，先看{'、'.join(positive[:3])}，航空和消费方向先别急着碰。"
    if "地缘冲突" in nature:
        return f"今天先按防御盘看，{'、'.join(positive[:3])}更容易有资金回流，{'、'.join(negative[:2])}不适合追。"
    if "宏观利率" in nature:
        return f"利率端还在施压，银行、保险、高股息相对更稳，{'、'.join(negative[:2])}先看不追。"
    if "避险资产" in nature:
        return f"只要美元和避险情绪不退，{'、'.join(positive[:3])}就还有相对收益。"
    if tone == "受益方向":
        return f"这条更偏资金防守切换，盘前先盯{'、'.join(positive[:3])}有没有持续性。"
    if tone == "承压方向":
        return f"风险偏好还没转强，{'、'.join(negative[:3])}更像反弹看待，不建议追高。"
    return f"先看轮动，不急着站队，盘中重点盯{'、'.join(positive[:2])}和{'、'.join(negative[:2])}的强弱变化。"


def enrich_news_items(news: list[dict[str, str]]) -> list[dict[str, Any]]:
    enriched: list[dict[str, Any]] = []
    for item in news:
        text = f"{item['title']} {item['body']}"
        tone, bias_text = classify_from_text(text)
        nature = infer_news_nature(text)
        positive_sectors, negative_sectors = infer_impacted_sectors(text)
        title_cn = infer_cn_headline(text, nature, item.get('source', ''))
        summary = infer_cn_summary(text, nature, item.get('source', ''))
        conclusion = infer_conclusion(text, nature, bias_text, tone, positive_sectors, negative_sectors)
        dimension = item.get('dimension', infer_dimension_label(nature))
        enriched.append(
            {
                **item,
                "dimension": dimension,
                "title_cn": title_cn,
                "summary_cn": summary,
                "conclusion_cn": conclusion,
                "tone": tone,
                "bias_text": bias_text,
                "positive_sectors": positive_sectors,
                "negative_sectors": negative_sectors,
            }
        )
    return enriched


def build_mapping(news: list[dict[str, str]]) -> dict[str, list[str]]:
    positive = ["黄金", "军工", "能源", "高股息", "电力", "有色"]
    negative = ["成长科技", "高估值题材", "出口链", "航空", "消费电子", "可选消费"]
    text = " ".join(f"{x['title']} {x['body']}" for x in news).lower()
    if "oil" in text or "crude" in text:
        positive = ["石油石化", "煤炭", "黄金", "电力", "资源股", "军工"]
        negative = ["航空", "航运下游", "高估值成长", "化工下游", "可选消费", "汽车零部件"]
    if "yield" in text or "fed" in text or "inflation" in text:
        positive = ["银行", "保险", "高股息", "资源股", "黄金", "电力"]
        negative = ["AI链", "半导体高估值", "创新药高估值", "小盘题材", "消费电子", "新能源高弹性"]
    return {"positive": positive[:6], "negative": negative[:6]}


def risk_bias(market: dict[str, dict[str, Any]], temp: dict[str, Any], news: list[dict[str, str]]) -> tuple[str, str]:
    negatives = 0
    positives = 0
    for key in ["道琼斯", "标普500", "纳斯达克", "恒生指数"]:
        val = market.get(key, {}).get("change_pct")
        if isinstance(val, (int, float)):
            if val > 0:
                positives += 1
            elif val < 0:
                negatives += 1
    if temp.get("score", 50) >= 65:
        positives += 1
    elif temp.get("score", 50) <= 40:
        negatives += 1
    text = " ".join(f"{x['title']} {x['body']}" for x in news).lower()
    if any(k in text for k in ["war", "tariff", "inflation", "selloff", "risk"]):
        negatives += 1
    if any(k in text for k in ["rebound", "gain", "rally", "stimulus"]):
        positives += 1
    if positives > negatives:
        return ("偏多", "偏进攻")
    if negatives > positives:
        return ("偏空", "防守")
    return ("中性", "均衡")


def render_markdown(market: dict[str, dict[str, Any]], temp: dict[str, Any], sector: dict[str, list[str]], news: list[dict[str, str]]) -> str:
    now = dt.datetime.now().strftime("%Y-%m-%d %H:%M")
    bias, a_share_style = risk_bias(market, temp, news)
    mapping = build_mapping(news)
    enriched_news = enrich_news_items(news)
    lines: list[str] = []
    lines.append("# 全球股市早间要闻（免费链路版）")
    lines.append("")
    lines.append(f"生成时间：{now}")
    lines.append("")
    lines.append(f"## 一句话总览")
    lines.append(f"- 今天全球风险偏好：**{bias}**")
    lines.append("")
    lines.append("## 隔夜市场速览")
    for key in ["道琼斯", "标普500", "纳斯达克", "恒生指数", "美元指数", "美债10Y", "原油", "黄金", "USD/CNH"]:
        data = market.get(key, {})
        source = data.get("source", "-")
        lines.append(f"- {key}：{data.get('change_pct', '-')}% / 现值 {data.get('price', '-')} / 来源 {source}")
    lines.append("")
    lines.append("## 今日早间要闻")
    if enriched_news:
        for idx, item in enumerate(enriched_news, 1):
            lines.append(f"- {idx}. [{item['dimension']}] {item['title_cn']}（来源：{item['source']}）")
            lines.append(f"  - 新闻：{item['summary_cn']}")
            lines.append(f"  - A股映射：偏利好{'、'.join(item['positive_sectors'])}；偏压制{'、'.join(item['negative_sectors'])}。")
            lines.append(f"  - 结论：{item['conclusion_cn']}")
            if item.get('href'):
                lines.append(f"  - 链接：{item['href']}")
    else:
        lines.append("- 今日未抓到高质量新闻结果，保留简版晨报。")
    lines.append("")
    lines.append("## 大盘体温")
    lines.append(f"- 评分：{temp.get('score', 50)}/100")
    lines.append(f"- 温度：{temp.get('label', '中性')}")
    lines.append(f"- 依据：涨停数 {temp.get('zt_count', 0)}")
    lines.append("")
    lines.append("## 板块映射")
    lines.append(f"- 可能受益：{'、'.join(mapping['positive'][:6])}")
    lines.append(f"- 可能承压：{'、'.join(mapping['negative'][:6])}")
    if sector.get('winners'):
        lines.append(f"- 当日板块强势参考：{'、'.join(sector['winners'][:3])}")
    if sector.get('losers'):
        lines.append(f"- 当日板块弱势参考：{'、'.join(sector['losers'][:3])}")
    lines.append("")
    lines.append("## 看涨 / 看跌")
    lines.append(f"- 看涨方向：{'、'.join(mapping['positive'][:5])}")
    lines.append(f"- 看跌方向：{'、'.join(mapping['negative'][:5])}")
    lines.append("")
    lines.append("## A股开盘前结论")
    lines.append(f"- 操作基调：**{a_share_style}**")
    lines.append("- 非交易时段不提供可执行买价；只给方向、优先级和开盘触发条件。")
    lines.append("")
    lines.append("## 数据来源")
    lines.append("- 新闻搜索主链路：Yahoo Search（免费）")
    lines.append("- 新闻搜索兜底：DuckDuckGo（免费）")
    lines.append("- 行情主链路：腾讯 / 新浪 / AKShare（按品类分流）")
    lines.append("- 行情兜底：yfinance（仅在主链路失败时启用）")
    lines.append("- 品类链路：")
    for name in ["上证指数", "深证成指", "创业板指", "恒生指数", "道琼斯", "标普500", "纳斯达克", "美元指数", "美债10Y", "原油", "黄金", "USD/CNH"]:
        lines.append(f"  - {name}：{MARKET_SOURCE_CHAINS[name]}")
    lines.append("")
    return "\n".join(lines) + "\n"


def render_json(market: dict[str, Any], temp: dict[str, Any], sector: dict[str, Any], news: list[dict[str, str]]) -> dict[str, Any]:
    bias, a_share_style = risk_bias(market, temp, news)
    mapping = build_mapping(news)
    enriched_news = enrich_news_items(news)
    missing = [name for name, data in market.items() if data.get("price") == "-" or data.get("change_pct") == "-"]
    return {
        "generated_at": dt.datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "risk_bias": bias,
        "a_share_style": a_share_style,
        "market": market,
        "temperature": temp,
        "sector": sector,
        "news": enriched_news,
        "mapping": mapping,
        "search_chain": ["yahoo", "duckduckgo"],
        "market_source_chain": MARKET_SOURCE_CHAINS,
        "market_snapshot_coverage": {
            "total": len(market),
            "missing": missing,
            "filled": len(market) - len(missing),
        },
    }


def main() -> int:
    parser = argparse.ArgumentParser(description="免费晨报生成器：Yahoo主搜 + DuckDuckGo兜底")
    parser.add_argument("--output", required=True, help="markdown 输出路径")
    parser.add_argument("--json-output", help="json 输出路径")
    args = parser.parse_args()

    news = choose_key_news(search_news())
    market = fetch_market_snapshot()
    news = synthesize_market_dimension_news(news, market)
    temp = fetch_a_share_temp()
    sector = fetch_sector_map()
    md = render_markdown(market, temp, sector, news)
    out_path = Path(args.output)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    out_path.write_text(md, encoding="utf-8")

    if args.json_output:
        j = render_json(market, temp, sector, news)
        Path(args.json_output).write_text(json.dumps(j, ensure_ascii=False, indent=2), encoding="utf-8")

    print(out_path)
    if args.json_output:
        print(args.json_output)
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

