def search_news() -> list[dict[str, str]]:
    items: list[dict[str, str]] = []
    seen: set[str] = set()

    for query in NEWS_QUERIES:
        for engine, cmd in [
            ("yahoo", [sys.executable, str(YAHOO_SEARCH), query, "-t", "d", "-m", "6", "--json"]),
            ("duckduckgo", [sys.executable, str(DDG_SEARCH), query, "-t", "d", "-m", "4", "--json"]),
        ]:
            try:
                data = run_json(cmd)
            except Exception:
                continue
            for row in data.get("results", []):
                href = unwrap_yahoo_url(row.get("href", "").strip())
                title = clean_title(row.get("title", "").strip())
                body = " ".join(row.get("body", "").strip().split())
                if not href or not title:
                    continue
                key = href
                if key in seen:
                    continue
                seen.add(key)
                items.append(
                    {
                        "title": title,
                        "href": href,
                        "body": body,
                        "source": domain(href) or engine,
                        "engine": engine,
                    }
                )
    return items[:12]


def fetch_market_snapshot() -> dict[str, dict[str, Any]]:
    out: dict[str, dict[str, Any]] = {}
    for name, config in MARKETS.items():
        category = config["category"]
        code = config["code"]
        fallback_ticker = config["fallback_ticker"]

        if category == "a_index":
            out[name] = _fetch_a_index_snapshot(code, fallback_ticker)
        elif category == "hk_index":
            out[name] = _fetch_hk_index_snapshot(code, fallback_ticker)
        elif category == "us_index":
            out[name] = _fetch_us_index_snapshot(code, fallback_ticker)
        elif category == "forex_sina":
            out[name] = _fetch_forex_snapshot(code, fallback_ticker)
        elif category == "futures_sina":
            out[name] = _fetch_futures_snapshot(code, fallback_ticker)
        elif category == "us10y":
            out[name] = _fetch_us10y_snapshot(fallback_ticker)
        elif category == "usdcnh":
            out[name] = _fetch_forex_snapshot(code, fallback_ticker, proxy_ok=True)
        elif category == "us_etf":
            try:
                out[name] = _fetch_yfinance_snapshot(fallback_ticker)
            except Exception as exc:
                out[name] = _format_market_result(None, None, "failed", error=f"yfinance:{exc}")
        else:
            out[name] = _format_market_result(None, None, "unsupported", error=f"unknown category: {category}")
    return out


