def normalize_for_dedupe(text: str) -> list[str]:
    text = re.sub(r"[^a-zA-Z0-9\u4e00-\u9fff ]+", " ", text.lower())
    stop = {
        "the", "and", "for", "with", "from", "that", "this", "into", "will", "hold", "above", "below",
        "what", "next", "week", "today", "latest", "news", "market", "markets", "stock", "stocks",
        "live", "commentary", "forecast", "price", "prices", "global",
    }
    return [tok for tok in text.split() if tok not in stop and len(tok) > 2]


def is_similar_news(a: dict[str, str], b: dict[str, str]) -> bool:
    title_a = set(normalize_for_dedupe(a.get("title", "")))
    title_b = set(normalize_for_dedupe(b.get("title", "")))
    if not title_a or not title_b:
        return False
    overlap = len(title_a & title_b)
    union = len(title_a | title_b) or 1
    body_a = " ".join(normalize_for_dedupe(a.get("body", "")))[:120]
    body_b = " ".join(normalize_for_dedupe(b.get("body", "")))[:120]
    same_source = a.get("source") == b.get("source")
    return (overlap / union >= 0.55) or (same_source and body_a and body_a == body_b)


def is_low_signal_news(item: dict[str, str]) -> bool:
    text = f"{item.get('title', '')} {item.get('body', '')}".lower()
    bad_patterns = [
        "breaking news, politics",
        "comprehensive news coverage",
        "news from japan",
        "homepage",
        "live |",
    ]
    weak_company_patterns = [
        "costco", "tesla", "apple", "nvidia", "amazon", "netflix", "microsoft",
        "earnings", "product launch", "store sales", "retailer",
    ]
    if any(p in text for p in bad_patterns):
        return True
    macro_keywords = ["oil", "gold", "yield", "treasury", "fed", "dollar", "inflation", "iran", "war", "stocks", "equities", "hong kong", "china", "nasdaq", "dow"]
    if any(p in text for p in weak_company_patterns) and sum(1 for kw in macro_keywords if kw in text) < 2:
        return True
    return sum(1 for kw in macro_keywords if kw in text) == 0


def choose_key_news(items: list[dict[str, str]]) -> list[dict[str, str]]:
    keywords = ["market", "stocks", "yield", "oil", "gold", "trade", "fed", "china", "hong kong", "dollar"]
    scored: list[tuple[int, str, dict[str, str]]] = []
    for item in items:
        text = f"{item['title']} {item['body']}".lower()
        score = sum(2 for kw in keywords if kw in text)
        if any(k in text for k in ["iran", "war", "oil", "yield", "fed", "treasury", "dollar", "usd", "nasdaq", "dow"]):
            score += 2
        score += source_weight(item.get("source", "")) * 2
        nature = infer_news_nature(text)
        dimension = infer_dimension_label(nature)
        scored.append((score, dimension, item))

    picks: list[dict[str, str]] = []
    target_dimensions = ["地缘 / 商品", "利率 / 美元", "全球股市"]

    for target in target_dimensions:
        for _, dimension, item in sorted(scored, key=lambda x: x[0], reverse=True):
            if dimension != target:
                continue
            if is_low_signal_news(item):
                continue
            if any(is_similar_news(item, existing) for existing in picks):
                continue
            item = {**item, "dimension": dimension}
            picks.append(item)
            break

    return picks[:3]


def should_replace_with_synthetic(item: dict[str, str], dimension: str) -> bool:
    text = f"{item.get('title', '')} {item.get('body', '')}".lower()
    if dimension == "全球股市":
        keys = ["dow", "nasdaq", "s&p", "hang seng", "equities", "stocks", "market"]
        return sum(1 for k in keys if k in text) < 2
    if dimension == "利率 / 美元":
        keys = ["yield", "treasury", "fed", "rate", "dollar", "usd"]
        return sum(1 for k in keys if k in text) < 2
    return False


