        cleaned.append(
            {
                "title": "Overnight equities snapshot",
                "href": "",
                "body": f"Dow {dji}%, S&P500 {spx}%, Nasdaq {ixic}%, Hang Seng {hsi}%.",
                "source": "market_snapshot",
                "engine": "synthetic",
                "dimension": "全球股市",
                "synthetic": True,
            }
        )

    order = {"地缘 / 商品": 0, "利率 / 美元": 1, "全球股市": 2}
    cleaned.sort(key=lambda x: order.get(x.get("dimension", "其他"), 9))
    return cleaned[:3]


def classify_from_text(text: str) -> tuple[str, str]:
    t = text.lower()
    bullish = ["rise", "rally", "gain", "rebound", "stimulus", "recover", "surge"]
    bearish = ["fall", "drop", "risk", "war", "inflation", "selloff", "tariff"]
    b = sum(1 for x in bullish if x in t)
    s = sum(1 for x in bearish if x in t)
    if b > s:
        return ("受益方向", "情绪偏多")
    if s > b:
        return ("承压方向", "情绪偏空")
    return ("中性方向", "情绪中性")


def infer_news_nature(text: str) -> str:
    t = text.lower()
    if any(k in t for k in ["war", "conflict", "iran", "middle east", "geopolitical", "oil", "crude", "energy", "gold"]):
        return "地缘冲突 / 大宗波动"
    if any(k in t for k in ["yield", "treasury", "fed", "rate", "inflation", "dollar", "usd", "fx", "currency"]):
        return "宏观利率 / 美元交易"
    if any(k in t for k in ["stocks", "equities", "futures", "market", "dow", "nasdaq", "s&p", "hong kong", "china"]):
        return "全球股市波动"
    return "综合市场信息"


def source_weight(source: str) -> int:
    s = (source or "").lower()
    weights = {
        "reuters.com": 5,
        "bloomberg.com": 5,
        "wsj.com": 5,
        "ft.com": 5,
        "cnbc.com": 4,
        "marketwatch.com": 4,
        "investing.com": 4,
        "economictimes.indiatimes.com": 3,
        "finance.yahoo.com": 3,
        "talkmarkets.com": 2,
    }
    return weights.get(s, 1)


def infer_dimension_label(nature: str) -> str:
    if nature == "地缘冲突 / 大宗波动":
        return "地缘 / 商品"
    if nature == "宏观利率 / 美元交易":
        return "利率 / 美元"
    if nature == "全球股市波动":
        return "全球股市"
    return "其他"


def infer_impacted_sectors(text: str) -> tuple[list[str], list[str]]:
    t = text.lower()
    positive: list[str] = []
    negative: list[str] = []

    if any(k in t for k in ["war", "conflict", "iran", "middle east"]):
        positive += ["黄金", "石油石化", "军工", "煤炭", "电力"]
        negative += ["航空", "消费电子", "高估值成长", "可选消费"]

    if any(k in t for k in ["oil", "crude", "energy"]):
        positive += ["油气", "煤炭", "资源股", "电力"]
        negative += ["航空", "化工下游", "物流运输"]

    if any(k in t for k in ["yield", "treasury", "fed", "rate", "inflation"]):
        positive += ["银行", "保险", "高股息"]
        negative += ["AI链", "半导体高估值", "创新药高估值", "新能源高弹性"]

    if any(k in t for k in ["gold", "dollar", "usd"]):
        positive += ["黄金", "有色", "出口防御链"]
        negative += ["人民币资产风险偏好", "外资敏感成长"]

    if not positive and not negative:
        positive = ["银行", "高股息", "资源股"]
        negative = ["高估值成长", "题材小票"]

    def uniq(items: list[str]) -> list[str]:
        seen: set[str] = set()
        out: list[str] = []
        for item in items:
            if item not in seen:
                seen.add(item)
                out.append(item)
        return out

    return uniq(positive)[:5], uniq(negative)[:5]


def infer_cn_headline(text: str, nature: str, source: str = "") -> str:
    t = text.lower()
    if source == "market_snapshot":
        return "隔夜全球股市普遍回落"
    if source == "rate_snapshot":
        return "美元与美债利率维持偏强"
    if "地缘冲突" in nature and any(k in t for k in ["oil", "crude", "energy"]):
        return "中东冲突延续，金油避险交易升温"
    if "地缘冲突" in nature and any(k in t for k in ["gold", "safe haven"]):
        return "避险交易未退，黄金高位震荡"
    if "宏观利率" in nature and any(k in t for k in ["yield", "treasury", "dollar", "usd"]):
        return "美元和美债收益率走强压制风险偏好"
    if any(k in t for k in ["equities", "selling equities", "cta"]):
        return "机构减配权益资产，转向美元与防御仓位"
    if any(k in t for k in ["stocks", "market", "futures"]):
        return "隔夜全球股市整体承压"
    return "隔夜宏观消息偏谨慎"


def infer_cn_summary(text: str, nature: str, source: str = "") -> str:
