        lines.append(f"  - {name}：{MARKET_SOURCE_CHAINS[name]}")
    lines.append("")
    return "\n".join(lines) + "\n"


def render_json(market: dict[str, Any], temp: dict[str, Any], sector: dict[str, Any], news: list[dict[str, str]]) -> dict[str, Any]:
    bias, a_share_style = risk_bias(market, temp, news)
    mapping = build_mapping(news)
    enriched_news = enrich_news_items(news)
    missing = [name for name, data in market.items() if data.get("price") == "-" or data.get("change_pct") == "-"]
    return {
        "generated_at": dt.datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "risk_bias": bias,
        "a_share_style": a_share_style,
        "market": market,
        "temperature": temp,
        "sector": sector,
        "news": enriched_news,
        "mapping": mapping,
        "search_chain": ["yahoo", "duckduckgo"],
        "market_source_chain": MARKET_SOURCE_CHAINS,
        "market_snapshot_coverage": {
            "total": len(market),
            "missing": missing,
            "filled": len(market) - len(missing),
        },
    }


def main() -> int:
    parser = argparse.ArgumentParser(description="免费晨报生成器：Yahoo主搜 + DuckDuckGo兜底")
    parser.add_argument("--output", required=True, help="markdown 输出路径")
    parser.add_argument("--json-output", help="json 输出路径")
    args = parser.parse_args()

    news = choose_key_news(search_news())
    market = fetch_market_snapshot()
    news = synthesize_market_dimension_news(news, market)
    temp = fetch_a_share_temp()
    sector = fetch_sector_map()
    md = render_markdown(market, temp, sector, news)
    out_path = Path(args.output)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    out_path.write_text(md, encoding="utf-8")

    if args.json_output:
        j = render_json(market, temp, sector, news)
        Path(args.json_output).write_text(json.dumps(j, ensure_ascii=False, indent=2), encoding="utf-8")

    print(out_path)
    if args.json_output:
        print(args.json_output)
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
